function createSupabaseAdmin(rows: unknown, error: { message: string } | null = null) {
  const inMock = vi.fn().mockResolvedValue({ data: rows, error });
  const selectMock = vi.fn(() => ({ in: inMock }));
  const fromMock = vi.fn(() => ({ select: selectMock }));

  return {
    supabaseAdmin: {
      from: fromMock,
